// ============================================================
// Valida entrada e monta prompt para o News Analyst
// Input esperado: { news_id, title, description, content, source, language, url }
// ============================================================
const input = $input.first().json;

if (!input.news_id) throw new Error('SWF-NewsAnalyst: news_id obrigatório');
if (!input.title)   throw new Error('SWF-NewsAnalyst: title obrigatório');

const articleText = [
  `TÍTULO: ${input.title}`,
  input.description ? `RESUMO: ${input.description}` : null,
  input.content     ? `CONTEÚDO:\n${input.content.substring(0, 3000)}` : null,
].filter(Boolean).join('\n\n');

const systemPrompt = `Você é um analista especializado em futebol da Copa do Mundo 2026.
Analise o artigo fornecido e retorne EXCLUSIVAMENTE um JSON válido conforme a estrutura abaixo.
Não adicione texto antes ou depois do JSON. Não use markdown. Retorne apenas JSON puro.

{
  "summary": "resumo objetivo em 2-3 frases em ${input.language === 'pt' ? 'português' : 'inglês'}",
  "impact_score": <número 0.0 a 1.0>,
  "impact_type": "<tactical|injury|form|controversy|lineup|suspension|weather|other>",
  "sentiment": "<positive|negative|neutral|very_positive|very_negative>",
  "key_insight": "o insight mais importante em uma frase",
  "tags": ["array", "de", "palavras-chave"],
  "topics": ["<injury|suspension|lineup|tactics|controversy|transfer|performance|weather|venue|historical>"],
  "affected_teams": ["nomes dos times mencionados no artigo"],
  "affected_players": ["nomes dos jogadores mencionados"],
  "relevance_to_wc2026": <número 0.0 a 1.0>
}

Critérios de impact_score:
0.9-1.0: lesão de titular confirmada, expulsão, mudança de escalação oficial
0.7-0.8: mudança tática significativa, controvérsia séria, suspensão
0.5-0.6: declarações de treinador, análise tática, estatísticas relevantes
0.3-0.4: cobertura geral, histórico, curiosidades
0.0-0.2: conteúdo tangencialmente relacionado à Copa

Critérios de relevance_to_wc2026: quão diretamente o artigo impacta a Copa 2026.`;

const startedAt = new Date().toISOString();

return [{
  json: {
    news_id: input.news_id,
    article_text: articleText,
    system_prompt: systemPrompt,
    language: input.language || 'en',
    source: input.source,
    started_at: startedAt,
  }
}];

// ============================================================
// Parse da resposta do GPT-4o
// Valida schema e extrai métricas de uso
// ============================================================
const prepData  = $('Prepare Prompt').first().json;
const apiResult = $input.first().json;

const finishedAt = new Date().toISOString();
const processingMs = new Date(finishedAt) - new Date(prepData.started_at);

// Extrai conteúdo e métricas de tokens
const message = apiResult.choices?.[0]?.message?.content;
const tokensUsed = apiResult.usage?.total_tokens || 0;

if (!message) {
  throw new Error(`GPT retornou resposta vazia. Status: ${JSON.stringify(apiResult.error || apiResult)}`);
}

let parsed;
try {
  // Remove backticks de markdown caso o modelo os inclua mesmo com json_object mode
  const clean = message.replace(/```json\n?|```/g, '').trim();
  parsed = JSON.parse(clean);
} catch (e) {
  throw new Error(`Falha ao parsear JSON do GPT: ${e.message}. Resposta: ${message.substring(0, 200)}`);
}

// Validação de campos obrigatórios
const required = ['summary', 'impact_score', 'impact_type', 'sentiment', 'key_insight'];
for (const field of required) {
  if (parsed[field] === undefined || parsed[field] === null) {
    throw new Error(`Campo obrigatório ausente na resposta GPT: ${field}`);
  }
}

// Sanitização de valores
const impactScore = Math.min(1, Math.max(0, parseFloat(parsed.impact_score) || 0));
const relevance   = Math.min(1, Math.max(0, parseFloat(parsed.relevance_to_wc2026) || impactScore));

const VALID_IMPACT_TYPES = ['tactical','injury','form','controversy','lineup','suspension','weather','other'];
const VALID_SENTIMENTS   = ['positive','negative','neutral','very_positive','very_negative'];
const VALID_TOPICS       = ['injury','suspension','lineup','tactics','controversy','transfer','performance','weather','venue','historical'];

const impactType = VALID_IMPACT_TYPES.includes(parsed.impact_type) ? parsed.impact_type : 'other';
const sentiment  = VALID_SENTIMENTS.includes(parsed.sentiment) ? parsed.sentiment : 'neutral';
const topics     = (parsed.topics || []).filter(t => VALID_TOPICS.includes(t));

return [{
  json: {
    news_id:             prepData.news_id,
    summary:             parsed.summary || '',
    impact_score:        impactScore,
    impact_type:         impactType,
    sentiment,
    key_insight:         parsed.key_insight || null,
    tags:                parsed.tags || [],
    topics,
    affected_teams:      parsed.affected_teams || [],
    affected_players:    parsed.affected_players || [],
    relevance_to_wc2026: relevance,
    raw_gpt_response:    parsed,
    // Auditoria
    ai_model:            apiResult.model || 'gpt-4o',
    prompt_version:      'v1.0',
    tokens_used:         tokensUsed,
    processing_ms:       processingMs,
    finished_at:         finishedAt,
  }
}];

// ============================================================
// Trata erro da chamada OpenAI
// Retorna objeto de erro estruturado para o caller persistir
// ============================================================
const prepData = $('Prepare Prompt').first().json;
const error = $input.first().json;

const errorMsg = error.error?.message || error.message || JSON.stringify(error);

console.error(`[SWF-NewsAnalyst] GPT error for news_id=${prepData.news_id}: ${errorMsg}`);

return [{
  json: {
    news_id: prepData.news_id,
    gpt_error: true,
    error_message: errorMsg,
    processing_ms: new Date() - new Date(prepData.started_at),
  }
}];
